mapper.select:
select thv.order_num orderNum, thv.total_price totalPrice, thv.pay_type payType, thvl.status status, thvl.create_time createTime, o.pay_order_num payOrderNum, ths.name hosSickName, th.hos_name hospitalName, tdu.name doctorName from t_hos_visit_log thvl left join t_hos_visit thv on thvl.hos_visit_id=thv.id left join t_order o on thv.order_num=o.order_num left join t_hos_sick ths on thvl.sick_id=ths.id left join t_doctor_user tdu on thvl.doctor_user_id=tdu.id left join t_hospital th on tdu.hospital_id=th.id
order by thvl.create_time desc
LIMIT #{page} ,#{limit}
